The following example blocks the RQST of the pgn = 0x5** (case 5) and replace the RQST of the pgn = 0x3** by the RQST of the pgn = 0x4** (case 3)
long Iso11783IL_OnRxMessage( pg * rxPG )
{
  if(rxPG.PGN == 0xEA00)
  {
    switch(rxPG.BYTE(1))
    {
    case 3:
      rxPG.BYTE(1) = 4;
      return 1;
    case 5:
      return 0;
    default:
      return 1;
    }
  }
  return 1;
}
